CREATE TABLE IF NOT EXISTS users (id BIGINT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(150) NOT NULL,email VARCHAR(150) NOT NULL UNIQUE,password_hash VARCHAR(255) NOT NULL,status ENUM('active','inactive','locked') DEFAULT 'active',created_at DATETIME DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL);
    CREATE TABLE IF NOT EXISTS roles (id BIGINT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100) NOT NULL UNIQUE,description TEXT NULL,created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
    CREATE TABLE IF NOT EXISTS permissions (id BIGINT AUTO_INCREMENT PRIMARY KEY,code VARCHAR(150) NOT NULL UNIQUE,name VARCHAR(150) NOT NULL,module VARCHAR(100) NOT NULL);
    CREATE TABLE IF NOT EXISTS user_roles (user_id BIGINT NOT NULL,role_id BIGINT NOT NULL,PRIMARY KEY(user_id,role_id));
    CREATE TABLE IF NOT EXISTS role_permissions (role_id BIGINT NOT NULL,permission_id BIGINT NOT NULL,PRIMARY KEY(role_id,permission_id));
    CREATE TABLE IF NOT EXISTS audit_logs (id BIGINT AUTO_INCREMENT PRIMARY KEY,user_id BIGINT NULL,action VARCHAR(150) NOT NULL,entity VARCHAR(100) NULL,entity_id VARCHAR(100) NULL,payload JSON NULL,ip_address VARCHAR(100) NULL,created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
    CREATE TABLE IF NOT EXISTS modules (id BIGINT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(150) NOT NULL,slug VARCHAR(150) NOT NULL UNIQUE,description TEXT NULL,fields_json JSON NULL,is_active BOOLEAN DEFAULT TRUE,created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
    CREATE TABLE IF NOT EXISTS module_records (id BIGINT AUTO_INCREMENT PRIMARY KEY,module_slug VARCHAR(150) NOT NULL,title VARCHAR(255) NULL,data_json JSON NULL,status VARCHAR(50) DEFAULT 'active',created_by BIGINT NULL,created_at DATETIME DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NULL);
    CREATE TABLE IF NOT EXISTS app_settings (id BIGINT AUTO_INCREMENT PRIMARY KEY,module_slug VARCHAR(150) NOT NULL,setting_key VARCHAR(150) NOT NULL,setting_value TEXT NULL,setting_type VARCHAR(50) DEFAULT 'text',updated_at DATETIME NULL,UNIQUE KEY module_setting(module_slug,setting_key));
    CREATE TABLE IF NOT EXISTS integration_events (id BIGINT AUTO_INCREMENT PRIMARY KEY,event_name VARCHAR(150) NOT NULL,source_app VARCHAR(100) NULL,payload JSON NULL,status VARCHAR(50) DEFAULT 'received',created_at DATETIME DEFAULT CURRENT_TIMESTAMP,processed_at DATETIME NULL);
    CREATE TABLE IF NOT EXISTS sync_logs (id BIGINT AUTO_INCREMENT PRIMARY KEY,source_app VARCHAR(100) NULL,target_app VARCHAR(100) NULL,event_name VARCHAR(150) NULL,status VARCHAR(50) DEFAULT 'pending',message TEXT NULL,payload JSON NULL,created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
